---@class StructFarmRecord
local StructFarmRecord = LxClass("StructFarmRecord", nil)
local StructSimplePlayerInfo = LXImport("..Struct.StructSimplePlayerInfo")

function StructFarmRecord:StructFarmRecord()
    --角色信息
    ---@type StructSimplePlayerInfo
    self.roleInfo = 0
    --时间 秒
    self.time = 0
    ---获得记录
    self.crops = {}
    --0收菜 1偷菜 2被偷
    self.type = 0
    --0成功 2失败
    self.result = 0
    --偷菜成功获得积分
    self.gainScore = 0
    --偷菜失败丢失积分
    self.loseScore = 0
end

function StructFarmRecord:CreateByPb(pb)
    --角色信息
    self.roleInfo = StructSimplePlayerInfo:New()
    self.roleInfo:CreateByPb(pb.roleInfo)
    --时间 秒
    self.time = pb.time or 0 
    --获得记录
    for _, cropInfo in ipairs(pb.crops) do
       self.crops[cropInfo.index] = {crop = cropInfo.crop,count=cropInfo.count,score=cropInfo.score}
    end
    --0收菜 1偷菜 2被偷
    self.type = pb.type
    --0成功 2失败
    self.result = pb.result
    --变化积分
    self.gainScore = pb.gainScore or 0
    self.loseScore = pb.loseScore or 0
end

