    --预计产量
    self.outputCount  = pb.outputCount
    -- 0-无 1-可偷取
    self.status  = pb.status
    -- 0-无 >0表示可以偷取时间
    self.predictTime= pb.predictTime
end

function StructNearbyFarm.CreateNearbyFarmObj(pb)
    local obj = StructNearbyFarm:New()
    obj:CreateByPb(pb)
